sys_script_include.script:
function HtmlRenderPrintableQRCodesA4(strPayload)
{
	var HtmlRenderQRCode = x_snc_devtools.HtmlRenderQRCode;
	var HtmlRenderPageA4 = x_snc_devtools.HtmlRenderPageA4;

    var strHtml = '';
    var strGrid = '';

    // A4 = 210×297mm. 3 cols × 4 rows = 12 codes.
    // Each cell ~60mm wide, ~65mm tall — leaves ~10mm gutters for cutting.
    var aCellStyles = [
        'display:inline-block',
        'width:60mm',
        'height:65mm',
        'margin:5mm',
        'padding:3mm',
        'border:0.3mm dashed #aaa',   // dashed border = cut guide
        'box-sizing:border-box',
        'text-align:center',
        'vertical-align:top'
		];
	var strCellStyle = aCellStyles.join(';');

    var aGridStyles = [
        'width:210mm',
        'text-align:center',
        'margin:0 auto'
		];
	var strGridStyle = aGridStyles.join(';');

    // Render the single QR code once
    var strSingleQR = HtmlRenderQRCode(strPayload, 5, 'cm');

    // Build 3 columns × 4 rows = 12 cells
    for (var row = 0; row < 4; row++)
    {
        for (var col = 0; col < 3; col++)
        {
            strGrid += '<div style="' + strCellStyle + '">'
                     +   strSingleQR
                     + '</div>';
        }
    }

    strHtml = '<div style="' + strGridStyle + '">' + strGrid + '</div>';

    strHtml = HtmlRenderPageA4(strHtml, 1, 1);

    return strHtml;
}
